import firebase_admin
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1

# Import the Firebase Admin SDK
firebase_admin.initialize_app()

def process_file_function(event, context):
    # Get the file bucket and name from the event object
    bucket_name = event['bucket']
    file_name = event['name']

    # Download the file from Cloud Storage to a local variable
    blob = storage.Client().get_bucket(bucket_name).blob(file_name)
    content = blob.download_as_string()

    # Write data to Firestore collection
    db = firestore.Client()
    doc_ref = db.collection('collection').document()
    doc_ref.set({
        'file_name': file_name,
        'content': content.decode('utf-8')
    })

    # Publish a message to Pub/Sub topic
    pubsub_client = pubsub_v1.PublisherClient()
    topic_path = 'projects/your-project-id/topics/your-topic-name'
    message = b"Hello, World!"
    pubsub_client.publish(topic_path, message)

# Set the function to trigger on Cloud Storage changes
def storage_bucket_event(event, context):
    process_file_function(event, context)